import org.hibernate.Session;
import org.hibernate.SessionFactory;
import org.hibernate.cfg.Configuration;
   
public class java_47998_SessionManager_A03 {
     
       private static SessionFactory sessionFactory;   //static so that it can be accessed from anywhere in the application, not just within this code block  - A01_SingleResponsibilityPrinciple (SRP)
       
       public static void main(String[] args){    
           initializeSessionfactory();    //invocation point for object initialization i.e., creating session factory instance here-AOI  		//Also ensures Singleton design pattern because once the SessionFactory is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - A02_BehavioralPrinciple
           //creating a new HelloWorld object – Bean Principle  	//AOI again		- SRP here- Singleton design pattern is enforced by the above code snippet. As soon as SessionFactory instance starts, it gets created (ISF) - ISFP		    
           createSession(1);    //creating a new HelloWorld object – Bean Principle  		//AOI again	- SRP here- Singleton design pattern is enforced by the above code snippet. As soon as SessionFactory instance starts, it gets created (ISF) - ISFP
       }    //end of main method()     AOM		  Behavioral Principle		//AOI again	- SRP here- Singleton design pattern is enforced by the above code snippet. As soon as SessionFactory instance starts, it gets created (ISF) - ISFP
       
       private static void initializeSessionfactory() {     //invocation point for object initialization i.e., creating session factory – AOI   		//Also ensures Singleton design pattern because once the SessionFactory is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
           Configuration configuration = new Configuration();   //invocation point for object initialization i.e., creating session factory – AOI   		//Also ensures Singleton design pattern because once the SessionFactory is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
           configuration.configure("hibernate.cfg.xml");     //invocation point for object initialization i.e., creating session factory – AOI   		//Also ensures Singleton design pattern because once the SessionFactory is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
           System.out.println("Hibernate Java Config loaded");     //invocation point for object initialization i.e., creating session factory – AOI   		//Also ensures Singleton design pattern because once the SessionFactory is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
           sessionFactory = configuration.buildSessionFactory();     //invocation point for object initialization i.e., creating session factory – AOI   		//Also ensures Singleton design pattern because once the SessionFactory is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
       }   //end of initializeSessionfactory method()     SI FP          Single Responsibility Principle      AOI here		//Also ensures Singleton design pattern because once the SessionFactory is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
       
       private static void createSession(int id){     //invocation point for object initialization i.e., creating session factory – AOI   		//Also ensures Singleton design pattern because once the SessionFactory is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
           if(sessionFactory == null){     //invocation point for object initialization i.e., creating session factory – AOI   		//Also ensures Singleton design pattern because once the SessionFactory is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
               initializeSessionfactory();     //invocation point for object initialization i.e., creating session factory – AOI   		//Also ensures Singleton design pattern because once the SessionFactory is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
           }   //end of if condition()     SI FP          Single Responsibility Principle      AOI here		//Also ensures Singleton design pattern because once the SessionFactory is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
           Session session = null;    //invocation point for object initialization i.e., creating a new HelloWorld – AOI     		//Also ensures Singleton design pattern because once the HibernateSession is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
           try{     //invocation point for object initialization i.e., creating a new session factory – AOI     		//Also ensures Singleton design pattern because once the HibernateSession is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
               if(sessionFactory == null){     //invocation point for object initialization i.e., creating session factory – AOI     		//Also ensures Singleton design pattern because once the HibernateSession is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
                   initializeSessionfactory();     //invocation point for object initialization i.e., creating session factory – AOI     		//Also ensures Singleton design pattern because once the HibernateSession is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
               }   //end of if condition()     SI FP          Single Responsibility Principle  AOI here		//Also ensures Singleton design pattern because once the HibernateSession is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
               session = sessionFactory.openSession();     //invocation point for object initialization i.e., creating a new hello world – AOI     		//Also ensures Singleton design pattern because once the Hibernate Session is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
           }   catch(Exception ex){     //invocation point for object initialization i.e., creating a new session factory – AOI     		//Also ensures Singleton design pattern because once the Hibernate Session is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
               ex.printStackTrace();     //invocation point for object initialization i.e., creating a new session factory – AOI     		//Also ensures Singleton design pattern because once the Hibernate Session is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
           }   //end of try-catch block()     SI FP          Single Responsibility Principle  AOI here		//Also ensures Singleton design pattern because once the Hibernate Session is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
           if(session != null){     //invocation point for object initialization i.e., creating a new session – AOI     		//Also ensures Singleton design pattern because once the Hibernate Session is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
               System.out.println("Session opened");     //invocation point for object initialization i.e., creating a new session – AOI     		//Also ensures Singleton design pattern because once the Hibernate Session is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
           }   //end of if condition()     SI FP          Single Responsibility Principle  AOI here		//Also ensures Singleton design pattern because once the Hibernate Session is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
       }   //end of createSession method()     SI FP          Single Responsibility Principle  AOI here		//Also ensures Singleton design pattern because once the Hibernate Session is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP
}   //end of class()     SI FP          Single Responsibility Principle  AOI here		//Also ensures Singleton design pattern because once the Hibernate Session is created, it should remain in memory and shouldn't be destroyed or recreated on request (LSP) - ISFP